import pandas as pd
def load_data(filename):
    return pd.read_csv(filename)

def filter_rows(df, min_value): # Generator version
    return (row for index, row in df.iterrows() if row['value'] > min_value)

def aggregate_data(filtered_df):
    return filtered_df.groupby('category')['value'].sum()
